fun main() {
    val animals = listOf("cat", "dog", "elephant", "ant", "bear")
    // filter length <= 3, then uppercase
    println(/* result */)
}

practice.solutionCode:
fun main() {
    val animals = listOf("cat", "dog", "elephant", "ant", "bear")
    val result = animals.filter { it.length <= 3 }.map { it.uppercase() }
    println(result)
}
